export const name = "repo";
export const version = "0.1.0";
export const description = "";

export function getIdentity() {
  return { name, version, description };
}

export function slugify(input) {
  const s = toStr(input).trim();
  if (!s) return "";
  const normalized = s.normalize ? s.normalize("NFKD") : s;
  // remove diacritics
  const withoutDiacritics = normalized.replace(/\p{M}/gu, "");
  const slug = withoutDiacritics
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");
  return slug;
}

export function truncate(input, length, suffix = "…") {
  const s = toStr(input);
  const n = Math.max(0, Number(length) || 0);
  if (!n) return "";
  if (s.length <= n) return s;
  const suff = toStr(suffix);
  const avail = Math.max(0, n - suff.length);
  if (avail === 0) return suff.slice(0, n);
  let candidate = s.slice(0, avail);
  const lastSpace = candidate.lastIndexOf(" ");
  if (lastSpace > -1) {
    candidate = candidate.slice(0, lastSpace).replace(/\s+$/g, "");
    if (!candidate) candidate = s.slice(0, avail);
  } else if (!candidate) {
    candidate = s.slice(0, avail);
  }
  return candidate + suff;
}

export function camelCase(input) {
  const s = toStr(input);
  const parts = s.match(/[\p{L}\p{N}]+/gu) || [];
  return parts
    .map((p, i) => {
      const lower = p.toLowerCase();
      if (i === 0) return lower;
      return lower.charAt(0).toUpperCase() + lower.slice(1);
    })
    .join("");
}

export function kebabCase(input) {
  const s = toStr(input).trim();
  if (!s) return "";
  const normalized = s.normalize ? s.normalize("NFKD") : s;
  const withoutDiacritics = normalized.replace(/\p{M}/gu, "");
  const parts = withoutDiacritics.match(/[\p{L}\p{N}]+/gu) || [];
  return parts.map((p) => p.toLowerCase()).join("-");
}

export function titleCase(input) {
  const s = toStr(input).trim();
  if (!s) return "";
  const words = s.split(/\s+/);
  return words
    .map((w) => {
      const [first, ...rest] = [...w];
      return first ? first.toUpperCase() + rest.join("").toLowerCase() : "";
    })
    .join(" ");
}

export function wordWrap(text, width = 80) {
  const s = toStr(text);
  const w = Math.max(1, Number(width) || 0);
  if (!s) return "";
  if (s.length <= w) return s;
  const words = s.split(/\s+/);
  const lines = [];
  let line = "";
  for (const word of words) {
    if (!line) {
      if (word.length > w) {
        lines.push(word);
      } else {
        line = word;
      }
    } else {
      if (line.length + 1 + word.length <= w) {
        line += " " + word;
      } else {
        lines.push(line);
        if (word.length > w) {
          lines.push(word);
          line = "";
        } else {
          line = word;
        }
      }
    }
  }
  if (line) lines.push(line);
  return lines.join("\n");
}

export function stripHtml(input) {
  const s = toStr(input);
  if (!s) return "";
  // remove script/style blocks
  let out = s.replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, "");
  out = out.replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, "");
  // strip tags
  out = out.replace(/<[^>]+>/g, "");
  // decode entities (named and numeric)
  out = out.replace(/&(#x?[0-9a-fA-F]+|[a-zA-Z]+);/g, (m, entity) => {
    if (entity[0] === "#") {
      const isHex = entity[1] === "x" || entity[1] === "X";
      const num = isHex ? parseInt(entity.slice(2), 16) : parseInt(entity.slice(1), 10);
      if (!isNaN(num)) return String.fromCodePoint(num);
      return m;
    }
    const named = entity.toLowerCase();
    const map = { amp: "&", lt: "<", gt: ">", quot: '"', apos: "'", nbsp: " " };
    return map[named] ?? m;
  });
  return out.replace(/\s+/g, " ").trim();
}

export function escapeRegex(input) {
  const s = toStr(input);
  if (!s) return "";
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

export function pluralize(input) {
  const s = toStr(input);
  if (!s) return "";
  const lower = s.toLowerCase();
  if (/(s|x|z|ch|sh)$/i.test(lower)) {
    return s + "es";
  }
  if (/[b-df-hj-np-tv-z]y$/i.test(lower)) {
    return s.slice(0, -1) + "ies";
  }
  if (/fe$/i.test(lower)) {
    return s.slice(0, -2) + "ves";
  }
  if (/f$/i.test(lower)) {
    return s.slice(0, -1) + "ves";
  }
  return s + "s";
}

export function levenshtein(a, b) {
  const A = toStr(a);
  const B = toStr(b);
  const m = A.length;
  const n = B.length;
  if (m === 0) return n;
  if (n === 0) return m;
  let prev = new Array(n + 1);
  for (let j = 0; j <= n; j++) prev[j] = j;
  for (let i = 1; i <= m; i++) {
    const cur = [i];
    for (let j = 1; j <= n; j++) {
      const cost = A[i - 1] === B[j - 1] ? 0 : 1;
      cur[j] = Math.min(cur[j - 1] + 1, prev[j] + 1, prev[j - 1] + cost);
    }
    prev = cur;
  }
  return prev[n];
}
